6	// HTML-escape user content. Escapes &, <, > — together that's enough to keep
7	// a hostile name from breaking out of any attribute or text content we emit
8	// via template literals; `<` alone defeats `</style>` / `</script>` breakouts.
9	export function esc(v) {
10	  if (v === null || v === undefined) return "";
11	  return String(v).replace(/[&<>]/g, (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;" }[c]));
12	}
