14	// Audit P38 + N33: every ISO date formatter parses + renders in UTC so a TD
15	// near a TZ boundary never sees an off-by-one weekday.
16	export function isoToUTCDate(iso) { return new Date(iso + "T00:00:00Z"); }
17	export function fmtIsoUTC(iso, opts) {
18	  return isoToUTCDate(iso).toLocaleDateString("en-US", { timeZone: "UTC", ...opts });
19	}
20	export function fmtDOW(iso) {
21	  if (!iso) return "";
22	  return iso + " (" + fmtIsoUTC(iso, { weekday: "short" }) + ")";
23	}
24	export function dowLong(iso) { return fmtIsoUTC(iso, { weekday: "long" }); }
25	export function fmtMDY(iso) {
26	  return iso ? fmtIsoUTC(iso, { month: "numeric", day: "numeric", year: "2-digit" }) : "";
27	}
