29	// Turn a FastAPI 422 validation `detail` list into something a TD can read.
30	// IMPORTANT: callers MUST render the result via `.textContent` (or equivalent)
31	// — values can contain user-controlled strings (subject lines, player names)
32	// and this function does no HTML escaping. Audit F19.
33	export function humanizeDetail(detail, statusText) {
34	  if (typeof detail === "string") return detail;
35	  if (Array.isArray(detail) && detail.length) {
36	    const shown = detail.slice(0, 3).map((d) => {
37	      const field = Array.isArray(d.loc) ? d.loc.filter((p) => p !== "body").join(".") : "";
38	      const msg = d.msg || d.type || "invalid";
39	      return field ? `${field}: ${msg}` : msg;
40	    }).join("; ");
41	    const extra = detail.length - 3;
42	    return extra > 0 ? `${shown} (+ ${extra} more)` : shown;
43	  }
44	  if (detail && typeof detail === "object" && detail.msg) return detail.msg;
45	  return statusText || "request failed";
46	}
