48	// CSV download from a 2D matrix; quotes everything to survive embedded commas
49	// and quotes. Used by every Setup CRUD + the t-shirt + assignment exports.
50	export function csvDownload(matrix, filename) {
51	  const csv = matrix
52	    .map((r) => r.map((c) => `"${String(c ?? "").replace(/"/g, '""')}"`).join(","))
53	    .join("\r\n");
54	  const url = URL.createObjectURL(new Blob([csv], { type: "text/csv" }));
55	  const a = document.createElement("a");
56	  a.href = url; a.download = filename + ".csv"; a.click();
57	  URL.revokeObjectURL(url);
58	}
