3008	  const rows = [...table.querySelectorAll("tbody tr")]
3009	    .filter((tr) => !tr.querySelector(".empty"))
3010	    .map((tr) => [...tr.children].filter((_, i) => keep[i]).map((td) => td.textContent.replace(/\s+/g, " ").trim()));
3011	  _csvDownload([headers, ...rows], name);
3012	}
