3078	// on open and restore focus on close. One pass at load — no per-site changes.
3079	(function _enhanceDetailDialogs() {
3080	  const obs = new MutationObserver((muts) => {
3081	    for (const m of muts) {
3082	      if (m.attributeName !== "class") continue;
3083	      const dlg = m.target;
3084	      const opening = dlg.classList.contains("detail-open");
3085	      const wasOpen = m.oldValue && m.oldValue.split(/\s+/).includes("detail-open");
3086	      if (opening && !wasOpen) {
3087	        // Audit P44: snapshot both the DOM node and the row id (if any) — when
3088	        // the dialog closes and the grid has been re-rendered, the original
3089	        // node is gone; falling back to a selector by row id lets focus land
3090	        // on the same logical record instead of body.
3091	        const a = document.activeElement;
3092	        const row = a && a.closest && a.closest(".tabulator-row[data-id]");
3093	        dlg._prevFocus = a;
3094	        dlg._prevRowId = row ? row.getAttribute("data-id") : null;
3095	        requestAnimationFrame(() => {
3096	          const f = dlg.querySelector('input:not([type="hidden"]):not([disabled]), select:not([disabled]), textarea:not([disabled])')
3097	            || dlg.querySelector('button:not([disabled])');
3098	          if (f) try { f.focus(); } catch (_) {}
3099	        });
3100	      } else if (!opening && wasOpen) {
3101	        const prev = dlg._prevFocus;
3102	        if (prev && prev.isConnected && typeof prev.focus === "function") {
3103	          try { prev.focus(); } catch (_) {}
3104	        } else if (dlg._prevRowId) {
3105	          const restored = document.querySelector(`.tabulator-row[data-id="${dlg._prevRowId}"]`);
3106	          if (restored) try { restored.focus(); } catch (_) {}
3107	        }
3108	      }
3109	    }
3110	  });
3111	  for (const dlg of document.querySelectorAll(".detail-pane")) {
3112	    if (!dlg.hasAttribute("role")) {
3113	      dlg.setAttribute("role", "dialog");
3114	      dlg.setAttribute("aria-modal", "true");
3115	      const title = dlg.querySelector(".detail-title");
3116	      if (title) {
3117	        if (!title.id) title.id = "dlg-" + Math.random().toString(36).slice(2, 8);
3118	        dlg.setAttribute("aria-labelledby", title.id);
3119	      }
3120	    }
3121	    obs.observe(dlg, { attributes: true, attributeOldValue: true, attributeFilter: ["class"] });
3122	  }
3123	})();
